create table if not exists `vehicles` (`id` INTEGER unsigned auto_increment, `brand` VARCHAR(255) not null, `name` VARCHAR(255) not null, `description` VARCHAR(255) not null, `plate` VARCHAR(255) not null, `isFavorite` tinyint(1) not null, `year` INTEGER not null, `color` VARCHAR(255) not null, `price` FLOAT not null, `createdAt` DATETIME not null, `updatedAt` DATETIME not null, primary key (`id`))